/* uuOS 内核类型定义 - 适用于 RISC-V 和 LoongArch */

#ifndef UUOS_TYPES_H
#define UUOS_TYPES_H

/* 空定义: 内核自包含,不依赖libc */
#define NULL ((void *)0)

/* 布尔类型 */
typedef enum { false = 0, true = 1 } bool;

/* 整数类型 */
typedef unsigned char      uint8_t;
typedef unsigned short     uint16_t;
typedef unsigned int       uint32_t;
typedef unsigned long long uint64_t;
typedef signed char        int8_t;
typedef signed short       int16_t;
typedef signed int         int32_t;
typedef signed long long   int64_t;

/* 指针大小类型 */
typedef unsigned long      size_t;
typedef long               ssize_t;
typedef unsigned long      uintptr_t;
typedef long               intptr_t;

/* 空类型 */
typedef __builtin_va_list  va_list;

#define va_start(v, l) __builtin_va_start(v, l)
#define va_arg(v, l)   __builtin_va_arg(v, l)
#define va_end(v)      __builtin_va_end(v)

/* 常量 */
#define PAGE_SIZE       4096
#define SECTOR_SIZE     512
#define ALIGN_UP(x, a)  (((x) + (a) - 1) & ~((a) - 1))
#define ALIGN_DOWN(x, a) ((x) & ~((a) - 1))
#define MIN(a, b)       ((a) < (b) ? (a) : (b))
#define MAX(a, b)       ((a) > (b) ? (a) : (b))

/* 内核堆大小 */
#define KERNEL_HEAP_SIZE (8 * 1024 * 1024)   /* 8MB */

/* IO 基地址 */
#ifdef __riscv
#define UART0_BASE        0x10000000UL
#define VIRTIO_MMIO_BASE  0x10001000UL
#define VIRTIO_MMIO_STRIDE 0x1000UL
#define VIRTIO_MMIO_NUM   8
#define KERNEL_BASE       0x80200000UL
#elif defined(__loongarch__)
#define UART0_BASE        0x1fe001e0UL
#define KERNEL_BASE       0x90000000UL
/* LoongArch virtio 通过 PCI, 不使用 MMIO 基地址 */
#else
/* 默认值 (用于 IDE 静态分析, 实际编译时由编译器定义架构宏) */
#define UART0_BASE        0x10000000UL
#define VIRTIO_MMIO_BASE  0x10001000UL
#define VIRTIO_MMIO_STRIDE 0x1000UL
#define VIRTIO_MMIO_NUM   8
#define KERNEL_BASE       0x80200000UL
#endif

#endif /* UUOS_TYPES_H */

/* uuOS 内核主入口 - RISC-V / LoongArch
 *
 * 启动流程:
 * 1. 架构汇编初始化 (entry.S) -> kernel_main()
 * 2. 初始化 UART / 控制台
 * 3. 初始化内存分配器
 * 4. 初始化 virtio-blk 并扫描块设备
 * 5. 挂载 EXT4 文件系统
 * 6. 初始化进程管理器和系统调用
 * 7. 扫描测试脚本并运行测试
 * 8. 关机
 */

#include "types.h"
#include "uart.h"
#include "printf.h"
#include "string.h"
#include "alloc.h"
#include "virtio_blk.h"
#include "ext4.h"
#include "proc.h"
#include "syscall.h"
#include "elf_loader.h"
#include "test_runner.h"
#include "sbi.h"

/* 全局 EXT4 文件系统上下文 (供 syscall 使用) */
ext4_fs_t g_ext4_fs;

/* 外部函数 */
extern void kernel_shutdown(void);

/* 早期启动输出 (在 UART 初始化之前) */
static void early_boot_msg(const char *msg) {
    while (*msg) {
        EARLY_PUTCHAR(*msg++);
    }
    EARLY_PUTCHAR('\r');
    EARLY_PUTCHAR('\n');
}

/* 打印启动横幅 */
static void print_banner(void) {
    printf("\n");
    printf("========================================\n");
    printf("  uuOS Kernel v2.0 - OS Challenge 2026\n");
    printf("  Team: AAA 李哥硬盘批发商\n");
    printf("  Arch: ");
#ifdef __riscv
    printf("RISC-V 64-bit\n");
#elif defined(__loongarch__)
    printf("LoongArch 64-bit\n");
#else
    printf("Unknown\n");
#endif
    printf("========================================\n\n");
}

/* 内核主函数 */
void kernel_main(void) {
    /* --- 阶段 0: 早期启动 --- */
    early_boot_msg("uuOS: Booting...");

    /* --- 阶段 1: 初始化控制台 --- */
    console_init();
    print_banner();

    printf("[init] 初始化内存分配器...\n");
    alloc_init();
    printf("[init] 可用堆内存: %d KB\n", (unsigned)(alloc_free_memory() / 1024));

    /* --- 阶段 2: 初始化块设备 --- */
    printf("[init] 扫描 virtio 块设备...\n");
    int blk_count = virtio_blk_init();

    if (blk_count == 0) {
        printf("[错误] 未找到任何块设备! 可能是:\n");
        printf("       1. QEMU 未挂载测试磁盘\n");
        printf("       2. virtio-blk MMIO 地址不匹配\n");
        printf("[错误] 系统无法继续, 将关机\n");
        kernel_shutdown();
        return;
    }

    /* 使用第一个块设备 (测试磁盘 x0) */
    virtio_blk_dev_t *test_disk = virtio_blk_get_device(0);
    if (!test_disk) {
        printf("[错误] 块设备 0 无效\n");
        kernel_shutdown();
        return;
    }

    virtio_blk_info(test_disk);

    /* --- 阶段 3: 挂载 EXT4 文件系统 --- */
    printf("[init] 挂载 EXT4 文件系统...\n");
    memset(&g_ext4_fs, 0, sizeof(g_ext4_fs));

    if (ext4_mount(&g_ext4_fs, test_disk) < 0) {
        printf("[错误] EXT4 挂载失败! 可能磁盘格式不是 EXT4\n");
        printf("[错误] 系统无法继续, 将关机\n");
        kernel_shutdown();
        return;
    }
    ext4_print_info(&g_ext4_fs);

    /* --- 阶段 4: 初始化进程管理和系统调用 --- */
    printf("[init] 初始化进程管理器...\n");
    proc_init();
    syscall_init();

    /* --- 阶段 5: 初始化测试运行器 --- */
    printf("[init] 初始化测试运行器...\n");
    test_runner_init();

    /* --- 阶段 6: 列出根目录内容 --- */
    printf("\n--- 磁盘根目录内容 ---\n");
    ext4_dir_entry_t dir_entries[256];
    int dir_count = ext4_readdir(&g_ext4_fs, EXT4_ROOT_INO, dir_entries, 256);
    for (int i = 0; i < dir_count; i++) {
        const char *type_str;
        switch (dir_entries[i].file_type) {
        case EXT4_FT_REG_FILE: type_str = "FILE"; break;
        case EXT4_FT_DIR:      type_str = "DIR";  break;
        case EXT4_FT_SYMLINK:  type_str = "LINK"; break;
        default:               type_str = "?";    break;
        }
        printf("  [%s] %s (inode=%d)\n",
               type_str, dir_entries[i].name, dir_entries[i].inode);
    }
    printf("  共 %d 个目录项\n\n", dir_count);

    /* --- 阶段 7: 发现测试脚本 --- */
    printf("[init] 扫描测试脚本...\n");
    int script_count = test_runner_discover(&g_ext4_fs);

    if (script_count == 0) {
        printf("[警告] 未发现任何测试脚本 (*_testcode.sh)\n");
        printf("[警告] 输出默认测试框架标记\n\n");

        /* 即使没有脚本，也输出标准框架 */
        /* 扫描根目录中的 ELF 文件作为备选 */
        printf("#### OS COMP TEST GROUP START default ####\n");

        int elf_count = 0;
        for (int i = 0; i < dir_count; i++) {
            if (dir_entries[i].file_type == EXT4_FT_REG_FILE &&
                str_endswith(dir_entries[i].name, ".elf")) {
                printf("[test] 发现 ELF: %s\n", dir_entries[i].name);

                /* 尝试加载并运行 ELF */
                elf_load_result_t result = elf_load(&g_ext4_fs,
                                                     dir_entries[i].inode,
                                                     USER_LOAD_BASE);
                if (result.success) {
                    printf("[test] %s 加载成功 (entry=0x%x)\n",
                           dir_entries[i].name, (unsigned)result.entry_point);
                } else {
                    printf("[test] %s 加载失败\n", dir_entries[i].name);
                }
                elf_count++;
            }
        }

        printf("#### OS COMP TEST GROUP END default ####\n\n");

        if (elf_count == 0) {
            printf("[警告] 也未发现 ELF 文件, 直接关机\n");
        }
    } else {
        /* --- 阶段 8: 运行测试 --- */
        test_runner_run_all(&g_ext4_fs);
    }

    /* --- 阶段 9: 关机 --- */
    printf("[info] 系统正常完成, 正在关机...\n");
    kernel_shutdown();

    /* 不应该到达这里 */
    while (1) { /* halt */ }
}

/* 字符串和内存操作函数实现 */

#include "string.h"
#include "alloc.h"

size_t strlen(const char *s) {
    const char *p = s;
    while (*p) p++;
    return (size_t)(p - s);
}

int strcmp(const char *a, const char *b) {
    while (*a && *a == *b) { a++; b++; }
    return (unsigned char)*a - (unsigned char)*b;
}

int strncmp(const char *a, const char *b, size_t n) {
    if (n == 0) return 0;
    while (n > 1 && *a && *a == *b) { a++; b++; n--; }
    return (unsigned char)*a - (unsigned char)*b;
}

char *strcpy(char *dst, const char *src) {
    char *d = dst;
    while ((*d++ = *src++));
    return dst;
}

char *strncpy(char *dst, const char *src, size_t n) {
    char *d = dst;
    while (n > 0 && (*d++ = *src++)) n--;
    while (n-- > 0) *d++ = '\0';
    return dst;
}

char *strcat(char *dst, const char *src) {
    char *d = dst;
    while (*d) d++;
    while ((*d++ = *src++));
    return dst;
}

char *strchr(const char *s, int c) {
    while (*s) {
        if (*s == (char)c) return (char *)s;
        s++;
    }
    if ((char)c == '\0') return (char *)s;
    return NULL;
}

int memcmp(const void *a, const void *b, size_t n) {
    const unsigned char *pa = (const unsigned char *)a;
    const unsigned char *pb = (const unsigned char *)b;
    for (size_t i = 0; i < n; i++) {
        if (pa[i] != pb[i]) return pa[i] - pb[i];
    }
    return 0;
}

void *memcpy(void *dst, const void *src, size_t n) {
    unsigned char *d = (unsigned char *)dst;
    const unsigned char *s = (const unsigned char *)src;
    for (size_t i = 0; i < n; i++) d[i] = s[i];
    return dst;
}

void *memmove(void *dst, const void *src, size_t n) {
    unsigned char *d = (unsigned char *)dst;
    const unsigned char *s = (const unsigned char *)src;
    if (d < s) {
        for (size_t i = 0; i < n; i++) d[i] = s[i];
    } else if (d > s) {
        for (size_t i = n; i > 0; i--) d[i - 1] = s[i - 1];
    }
    return dst;
}

void *memset(void *s, int c, size_t n) {
    unsigned char *p = (unsigned char *)s;
    for (size_t i = 0; i < n; i++) p[i] = (unsigned char)c;
    return s;
}

int atoi(const char *s) {
    int sign = 1, val = 0;
    while (*s == ' ' || *s == '\t') s++;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') s++;
    while (*s >= '0' && *s <= '9') {
        val = val * 10 + (*s - '0');
        s++;
    }
    return sign * val;
}

char *strdup(const char *s) {
    size_t len = strlen(s);
    char *d = (char *)kmalloc(len + 1);
    if (d) {
        memcpy(d, s, len);
        d[len] = '\0';
    }
    return d;
}

char *strndup(const char *s, size_t n) {
    size_t len = strlen(s);
    if (len > n) len = n;
    char *d = (char *)kmalloc(len + 1);
    if (d) {
        memcpy(d, s, len);
        d[len] = '\0';
    }
    return d;
}

char *strstr(const char *haystack, const char *needle) {
    if (!*needle) return (char *)haystack;
    size_t needle_len = strlen(needle);
    while (*haystack) {
        if (*haystack == *needle && strncmp(haystack, needle, needle_len) == 0)
            return (char *)haystack;
        haystack++;
    }
    return NULL;
}

int str_endswith(const char *s, const char *suffix) {
    size_t slen = strlen(s);
    size_t suflen = strlen(suffix);
    if (slen < suflen) return 0;
    return strcmp(s + slen - suflen, suffix) == 0;
}

/* 字符串和内存操作函数 */

#ifndef UUOS_STRING_H
