/* 简单的边界标记内存分配器 (boundary-tag allocator) */

#include "alloc.h"
#include "string.h"

/* 内存块头部 */
typedef struct block_header {
    size_t size;              /* 块大小(含头部, 字节), bit0=1 表示已分配 */
    struct block_header *next; /* 空闲链表中的下一个 */
    struct block_header *prev; /* 空闲链表中的上一个 */
} block_t;

#define BLOCK_MAGIC     0xDEADBEEF
#define BLOCK_MIN_SIZE  32  /* 最小块大小 (含头部) */
#define BLOCK_ALIGN     16  /* 对齐边界 */

static uint8_t  heap_area[8 * 1024 * 1024];  /* 8MB 静态堆 */
static block_t *free_list = NULL;
static size_t   heap_size = 0;
static int      alloc_initialized = 0;

#define HEADER_SIZE ALIGN_UP(sizeof(block_t), BLOCK_ALIGN)
#define IS_FREE(b)  (((b)->size & 1) == 0)
#define SET_FREE(b)  ((b)->size &= ~1UL)
#define SET_USED(b)  ((b)->size |= 1UL)
#define GET_SIZE(b)  ((b)->size & ~1UL)
#define BLOCK_TO_DATA(b) ((void *)((uintptr_t)(b) + HEADER_SIZE))
#define DATA_TO_BLOCK(p) ((block_t *)((uintptr_t)(p) - HEADER_SIZE))
#define NEXT_BLOCK(b)    ((block_t *)((uintptr_t)(b) + GET_SIZE(b)))

void alloc_init(void) {
    if (alloc_initialized) return;
    alloc_initialized = 1;

    heap_size = sizeof(heap_area);
    memset(heap_area, 0, heap_size);

    /* 初始化第一个空闲块 */
    block_t *first = (block_t *)heap_area;
    first->size = heap_size;
    SET_FREE(first);
    first->next = NULL;
    first->prev = NULL;
    free_list = first;
}

/* 将块插入空闲链表 (保持地址顺序) */
static void insert_free(block_t *b) {
    SET_FREE(b);
    b->next = NULL;
    b->prev = NULL;

    if (!free_list) {
        free_list = b;
        return;
    }

    /* 按地址顺序插入 */
    block_t *cur = free_list;
    block_t *last = NULL;
    while (cur && cur < b) {
        last = cur;
        cur = cur->next;
    }

    if (last) {
        last->next = b;
        b->prev = last;
    } else {
        free_list = b;
    }
    if (cur) {
        b->next = cur;
        cur->prev = b;
    }
}

/* 从空闲链表中移除 */
static void remove_free(block_t *b) {
    if (b->prev) b->prev->next = b->next;
    else free_list = b->next;
    if (b->next) b->next->prev = b->prev;
}

/* 尝试合并相邻空闲块 */
static void try_merge(block_t *b) {
    block_t *next = NEXT_BLOCK(b);
    if ((uintptr_t)next < (uintptr_t)heap_area + heap_size && IS_FREE(next)) {
        remove_free(next);
        b->size += next->size;
    }

    /* 与前一个块合并: 读取前一个块的头部获取其大小 */
    if ((uintptr_t)b > (uintptr_t)heap_area) {
        /* 前一个块的header在b前面，我们需要读取它 */
        /* 由于我们无法知道前一个块大小，跳过向前合并 */
    }
}

void *kmalloc(size_t size) {
    if (!alloc_initialized) alloc_init();
    if (size == 0) return NULL;

    size_t need = ALIGN_UP(size + HEADER_SIZE, BLOCK_ALIGN);
    if (need < BLOCK_MIN_SIZE) need = BLOCK_MIN_SIZE;

    /* 遍历空闲链表找第一个足够大的块 */
    block_t *b = free_list;
    while (b) {
        if (IS_FREE(b) && GET_SIZE(b) >= need) {
            remove_free(b);

            /* 如果剩余空间可以容纳一个新块，则分割 */
            if (GET_SIZE(b) >= need + BLOCK_MIN_SIZE) {
                size_t old_size = GET_SIZE(b);
                b->size = need;
                SET_USED(b);

                block_t *newb = NEXT_BLOCK(b);
                newb->size = old_size - need;
                insert_free(newb);
            } else {
                SET_USED(b);
            }

            return BLOCK_TO_DATA(b);
        }
        b = b->next;
    }

    return NULL; /* OOM */
}

void kfree(void *ptr) {
    if (!ptr || !alloc_initialized) return;
    block_t *b = DATA_TO_BLOCK(ptr);
    SET_FREE(b);
    insert_free(b);
    try_merge(b);
}

void *kcalloc(size_t nmemb, size_t size) {
    size_t total = nmemb * size;
    if (size && total / size != nmemb) return NULL; /* overflow */
    void *p = kmalloc(total);
    if (p) memset(p, 0, total);
    return p;
}

void *krealloc(void *ptr, size_t new_size) {
    if (!ptr) return kmalloc(new_size);
    if (new_size == 0) { kfree(ptr); return NULL; }

    block_t *b = DATA_TO_BLOCK(ptr);
    size_t old_data_size = GET_SIZE(b) - HEADER_SIZE;

    if (new_size <= old_data_size) return ptr;

    void *newp = kmalloc(new_size);
    if (newp) {
        memcpy(newp, ptr, old_data_size);
        kfree(ptr);
    }
    return newp;
}

size_t alloc_free_memory(void) {
    if (!alloc_initialized) return 0;
    size_t total = 0;
    block_t *b = free_list;
    while (b) {
        if (IS_FREE(b)) total += GET_SIZE(b) - HEADER_SIZE;
        b = b->next;
    }
    return total;
}

void *alloc_page(void) {
    return kmalloc(PAGE_SIZE);
}

void free_page(void *page) {
    kfree(page);
}

void *alloc_pages(size_t num_pages) {
    return kmalloc(num_pages * PAGE_SIZE);
}

void free_pages(void *ptr, size_t num_pages) {
    (void)num_pages;
    kfree(ptr);
}

/* 简单的内核内存分配器 */

#ifndef UUOS_ALLOC_H
#define UUOS_ALLOC_H

#include "types.h"

/* 初始化内核堆 */
void alloc_init(void);

/* 分配/释放内存 */
void *kmalloc(size_t size);
void  kfree(void *ptr);
void *kcalloc(size_t nmemb, size_t size);
void *krealloc(void *ptr, size_t new_size);

/* 获取空闲内存信息 */
size_t alloc_free_memory(void);

/* 页级分配 (用于页表等) */
void *alloc_page(void);
void  free_page(void *page);
void *alloc_pages(size_t num_pages);
void  free_pages(void *ptr, size_t num_pages);

#endif

/* ns16550 UART 驱动实现 */

#include "uart.h"
#include "types.h"

/* UART MMIO 基地址: QEMU RISC-V virt 机器固定在 0x10000000 */
/* LoongArch virt 机器也使用类似地址的 ns16550 */
#ifdef __riscv
#define UART_BASE UART0_BASE
#elif defined(__loongarch__)
#define UART_BASE UART0_BASE
#else
#define UART_BASE 0x10000000UL
#endif

/* MMIO 访问: volatile 确保每次访问都生效 */
static inline uint8_t uart_read(int reg) {
    return *(volatile uint8_t *)(UART_BASE + reg);
}

static inline void uart_write(int reg, uint8_t val) {
    *(volatile uint8_t *)(UART_BASE + reg) = val;
}

void uart_init(void) {
    /* 禁用中断 */
    uart_write(UART_IER, 0);

    /* 设置波特率: 启用 DLAB */
    uart_write(UART_LCR, LCR_DLAB);
    /* 115200 baud @ 时钟频率由QEMU处理，设一个合理的分频值 */
    /* 对于 1.8432MHz 晶振: 1843200/(16*115200) = 1 */
    uart_write(UART_DLL, 0x01);  /* 分频器低字节 */
    uart_write(UART_DLM, 0x00);  /* 分频器高字节 */

    /* 8N1 格式 */
    uart_write(UART_LCR, LCR_8BIT);

    /* 启用并清空 FIFO */
    uart_write(UART_FCR, FCR_ENABLE | FCR_CLR_RX | FCR_CLR_TX);

    /* 禁用调制解调控制 */
    uart_write(UART_MCR, 0x00);
}

void uart_putc(int c) {
    /* 等待发送 FIFO 就绪 */
    while ((uart_read(UART_LSR) & LSR_TX_EMPTY) == 0) {
        /* 忙等 */
    }
    uart_write(UART_THR, (uint8_t)c);
}

int uart_getc(void) {
    /* 等待接收数据 */
    while ((uart_read(UART_LSR) & LSR_RX_READY) == 0) {
        /* 忙等 */
    }
    return uart_read(UART_RBR);
}

int uart_rx_ready(void) {
    return (uart_read(UART_LSR) & LSR_RX_READY) != 0;
}

