/* --- vsnprintf 核心实现 --- */

static int vsnprintf_core(char *buf, size_t size, const char *fmt, va_list ap,
                          int (*emit)(int c, void *ctx), void *ctx)
{
    char *p = buf;
    char *end = buf + size;
    int total = 0;

    /* 写入一个字符 (到缓冲区或回调) */
    #define EMIT(c) do { \
        total++; \
        if (emit) { emit(c, ctx); } \
        else if (p && p < end) { *p++ = (char)(c); } \
        else if (p && size == 0) { /* truncate */ } \
        else if (p) { *p = '\0'; } \
    } while (0)

    while (*fmt) {
        if (*fmt != '%') {
            EMIT(*fmt++);
            continue;
        }

        fmt++; /* 跳过 '%' */

        /* 解析标志 */
        int pad_zero = 0;
        int width = 0;
        int long_flag = 0;
        int long_long_flag = 0;

        if (*fmt == '0') { pad_zero = 1; fmt++; }

        while (*fmt >= '0' && *fmt <= '9') {
            width = width * 10 + (*fmt - '0');
            fmt++;
        }

        if (*fmt == 'l') {
            long_flag = 1; fmt++;
            if (*fmt == 'l') { long_long_flag = 1; long_flag = 0; fmt++; }
        }

        if (*fmt == 'z') { /* size_t - 按指针大小处理 */
            fmt++;
            if (sizeof(size_t) == 8) long_flag = 2;
        }

        /* 格式说明符 */
        char spec = *fmt;
        if (!spec) break;
        fmt++;

        switch (spec) {
        case 's': {
            const char *s = va_arg(ap, const char *);
            if (!s) s = "(null)";
            int slen = strlen(s);
            while (!pad_zero && width > slen) { EMIT(' '); width--; }
            while (*s) EMIT(*s++);
            while (width > slen) { EMIT('0'); width--; }
            break;
        }
        case 'c': {
            int c = va_arg(ap, int);
            while (!pad_zero && width > 1) { EMIT(' '); width--; }
            EMIT(c);
            while (width > 1) { EMIT(' '); width--; }
            break;
        }
        case 'd':
        case 'i': {
            long long val;
            if (long_long_flag) val = va_arg(ap, long long);
            else if (long_flag) val = va_arg(ap, long);
            else val = va_arg(ap, int);

            int neg = 0;
            if (val < 0) { neg = 1; val = -val; }

            char tmp[32];
            int tlen = 0;
            if (val == 0) { tmp[tlen++] = '0'; }
            else {
                while (val > 0) {
                    tmp[tlen++] = '0' + (int)(val % 10);
                    val /= 10;
                }
            }
            if (neg) width--;
            if (pad_zero) {
                if (neg) EMIT('-');
                while (width > tlen) { EMIT('0'); width--; }
                if (neg && !pad_zero) EMIT('-');
            } else {
                while (width > tlen) { EMIT(' '); width--; }
                if (neg) EMIT('-');
            }
            while (tlen > 0) EMIT(tmp[--tlen]);
            break;
        }
        case 'u': {
            unsigned long long val;
            if (long_long_flag) val = va_arg(ap, unsigned long long);
            else if (long_flag) val = va_arg(ap, unsigned long);
            else val = va_arg(ap, unsigned int);

            char tmp[32];
            int tlen = 0;
            if (val == 0) { tmp[tlen++] = '0'; }
            else {
                while (val > 0) {
                    tmp[tlen++] = '0' + (int)(val % 10);
                    val /= 10;
                }
            }
            if (pad_zero) {
                while (width > tlen) { EMIT('0'); width--; }
            } else {
                while (width > tlen) { EMIT(' '); width--; }
            }
            while (tlen > 0) EMIT(tmp[--tlen]);
            break;
        }
        case 'x': {
            unsigned long long val;
            if (long_long_flag) val = va_arg(ap, unsigned long long);
            else if (long_flag) val = va_arg(ap, unsigned long);
            else val = va_arg(ap, unsigned int);

            char tmp[32];
            int tlen = 0;
            if (val == 0) { tmp[tlen++] = '0'; }
            else {
                while (val > 0) {
                    int d = (int)(val & 0xF);
                    tmp[tlen++] = (char)(d < 10 ? '0' + d : 'a' + d - 10);
                    val >>= 4;
                }
            }
            if (pad_zero) {
                while (width > tlen) { EMIT('0'); width--; }
            } else {
                while (width > tlen) { EMIT(' '); width--; }
            }
            while (tlen > 0) EMIT(tmp[--tlen]);
            break;
        }
        case 'p': {
            uintptr_t val = (uintptr_t)va_arg(ap, void *);
            EMIT('0'); EMIT('x');
            if (val == 0) {
                EMIT('0');
            } else {
                char tmp[20];
                int tlen = 0;
                while (val > 0) {
                    int d = (int)(val & 0xF);
                    tmp[tlen++] = (char)(d < 10 ? '0' + d : 'a' + d - 10);
                    val >>= 4;
                }
                while (tlen > 0) EMIT(tmp[--tlen]);
            }
            break;
        }
        case '%':
            EMIT('%');
            break;
        default:
            EMIT('%');
            EMIT(spec);
            break;
        }
    }

    if (p && p < end) *p = '\0';
    else if (p && size > 0) *(p - 1) = '\0';

    #undef EMIT
    return total;
}

int vsnprintf(char *buf, size_t size, const char *fmt, va_list ap) {
    return vsnprintf_core(buf, size, fmt, ap, NULL, NULL);
}

int snprintf(char *buf, size_t size, const char *fmt, ...) {
    va_list ap;
    va_start(ap, fmt);
    int ret = vsnprintf(buf, size, fmt, ap);
    va_end(ap);
    return ret;
}

int printf(const char *fmt, ...) {
    va_list ap;
    va_start(ap, fmt);
    int ret = vsnprintf_core(NULL, 0, fmt, ap, out_char, NULL);
    va_end(ap);
    return ret;
}

