/* SBI 调用: 通过 ecall 指令从 S-mode 调用 M-mode OpenSBI */

/* SBI 扩展 ID */
#define SBI_EXT_BASE            0x10
#define SBI_EXT_TIME            0x54494D45
#define SBI_EXT_HSM             0x48534D
#define SBI_EXT_SRST            0x53525354
#define SBI_EXT_DBCN            0x4442434E

/* SBI 函数 */
#define SBI_BASE_GET_SPEC_VERSION   0
#define SBI_BASE_GET_IMP_ID         1
#define SBI_BASE_GET_IMP_VERSION    2
#define SBI_BASE_GET_MVENDORID      3
#define SBI_BASE_GET_MARCHID        4
#define SBI_BASE_GET_MIMPID         5

#define SBI_TIME_SET_TIMER          0

#define SBI_HSM_HART_START          0
#define SBI_HSM_HART_STOP           1
#define SBI_HSM_HART_GET_STATUS     2

#define SBI_SRST_SYSTEM_RESET       0

#define SBI_DBCN_CONSOLE_WRITE      0
#define SBI_DBCN_CONSOLE_READ       1

/* SBI 错误码 */
#define SBI_SUCCESS              0
#define SBI_ERR_FAILED          -1
#define SBI_ERR_NOT_SUPPORTED   -2
#define SBI_ERR_INVALID_PARAM   -3

/* 关机类型 */
#define SBI_SRST_RESET_TYPE_SHUTDOWN    0x00000000
#define SBI_SRST_RESET_TYPE_COLD_REBOOT 0x00000001
#define SBI_SRST_RESET_TYPE_WARM_REBOOT 0x00000002
#define SBI_SRST_REASON_NONE            0x00000000
#define SBI_SRST_REASON_SYSFAIL         0x00000001

/* 类型检查 */
#ifdef __riscv

/* RISC-V SBI 调用: 使用 ecall 指令 */
static inline struct sbiret {
    long error;
    long value;
} sbi_ecall(long arg0, long arg1, long arg2,
            long arg3, long arg4, long arg5,
            long fid, long eid)
{
    struct sbiret ret;
    register long a0 __asm__("a0") = arg0;
    register long a1 __asm__("a1") = arg1;
    register long a2 __asm__("a2") = arg2;
    register long a3 __asm__("a3") = arg3;
    register long a4 __asm__("a4") = arg4;
    register long a5 __asm__("a5") = arg5;
    register long a6 __asm__("a6") = fid;
    register long a7 __asm__("a7") = eid;

    __asm__ __volatile__(
        "ecall"
        : "+r"(a0), "+r"(a1)
        : "r"(a2), "r"(a3), "r"(a4), "r"(a5), "r"(a6), "r"(a7)
        : "memory");

    ret.error = a0;
    ret.value = a1;
    return ret;
}

/* 通过 SBI 控制台输出 (早期启动使用) */
static inline void sbi_console_putchar(int c) {
    sbi_ecall(c, 0, 0, 0, 0, 0, SBI_DBCN_CONSOLE_WRITE, SBI_EXT_DBCN);
}

/* 系统关机 */
static inline void sbi_shutdown(void) {
    sbi_ecall(SBI_SRST_RESET_TYPE_SHUTDOWN, SBI_SRST_REASON_NONE,
              0, 0, 0, 0, SBI_SRST_SYSTEM_RESET, SBI_EXT_SRST);
}

/* 设置定时器 */
static inline void sbi_set_timer(uint64_t stime_value) {
    sbi_ecall(stime_value, 0, 0, 0, 0, 0, SBI_TIME_SET_TIMER, SBI_EXT_TIME);
}

#define SHUTDOWN() sbi_shutdown()
#define EARLY_PUTCHAR(c) sbi_console_putchar(c)

#else
/* 非 RISC-V 平台 (LoongArch) 使用内联汇编实现类似功能 */

#ifdef __loongarch__

/* LoongArch 没有 SBI，使用 ACPI 或直接 QEMU 关机方式 */
/* 对于 QEMU，可以使用 gpio 关机或直接写 ACPI */

static inline void la_shutdown(void) {
    /* QEMU virt 机器: 写 0x5555 到 0x1000000 触发关机 (gpio) */
    /* 另一种方式: 通过 ACPI PM1a 端口 */
    /* QEMU loongarch64 virt 使用 ACPI */
    /* 尝试直接调用 exit，先用简单的无限循环+通知方式 */

    /* QEMU test device: 写特定值关机 */
    /* 对于 QEMU loongarch64, 使用 isa-debug-exit 或直接调用 SYSCALL */
    /* 使用最简单的 shutdown: 通过 magic address */
    volatile uint16_t *p = (volatile uint16_t *)0x10000000UL;
    *p = 0x5555; /* QEMU gpio shutdown */

    /* 如果上面不工作，尝试 semihosting */
    __asm__ __volatile__(
        "li.d $r4, 0x20026\n"  /* ADP_Stopped_ApplicationExit */
        "li.d $r5, 0\n"
        "break 0\n"
        ::: "r4", "r5");

    /* 最后的办法: 死循环，由 QEMU 超时结束 */
    while (1) { __asm__ __volatile__("idle 0"); }
}

static inline void la_early_putchar(int c) {
    /* LoongArch UART: 直接写 UART MMIO */
    volatile uint8_t *uart = (volatile uint8_t *)UART0_BASE;
    /* 等待发送就绪 */
    while ((*(volatile uint8_t *)(UART0_BASE + 5) & 0x20) == 0);
    *uart = (uint8_t)c;
}

#define SHUTDOWN() la_shutdown()
#define EARLY_PUTCHAR(c) la_early_putchar(c)

#else
/* 通用回退 */
#define SHUTDOWN() do { while(1); } while(0)
#define EARLY_PUTCHAR(c) do { (void)(c); } while(0)
#endif
#endif

/* 平台无关的关机函数 */
void kernel_shutdown(void);

#endif /* UUOS_SBI_H */

/* virtio-blk 块设备驱动实现 - 基于 MMIO (legacy 接口) */

#include "virtio_blk.h"
#include "alloc.h"
#include "string.h"
#include "printf.h"
#include "types.h"

/* --- MMIO 寄存器偏移 (legacy virtio) --- */
#define VIRTIO_MMIO_MAGIC_VALUE         0x000
#define VIRTIO_MMIO_VERSION             0x004
#define VIRTIO_MMIO_DEVICE_ID           0x008
#define VIRTIO_MMIO_VENDOR_ID           0x00C
#define VIRTIO_MMIO_DEVICE_FEATURES     0x010
#define VIRTIO_MMIO_DEVICE_FEATURES_SEL 0x014
#define VIRTIO_MMIO_DRIVER_FEATURES     0x020
#define VIRTIO_MMIO_DRIVER_FEATURES_SEL 0x024
#define VIRTIO_MMIO_GUEST_PAGE_SIZE     0x028
#define VIRTIO_MMIO_QUEUE_SEL           0x030
#define VIRTIO_MMIO_QUEUE_NUM_MAX       0x034
#define VIRTIO_MMIO_QUEUE_NUM           0x038
#define VIRTIO_MMIO_QUEUE_ALIGN         0x03C
#define VIRTIO_MMIO_QUEUE_PFN           0x040
#define VIRTIO_MMIO_QUEUE_NOTIFY        0x050
#define VIRTIO_MMIO_INTERRUPT_STATUS    0x060
#define VIRTIO_MMIO_INTERRUPT_ACK       0x064
#define VIRTIO_MMIO_STATUS              0x070
#define VIRTIO_MMIO_CONFIG              0x100

/* 设备状态位 */
#define VIRTIO_STATUS_ACKNOWLEDGE       1
#define VIRTIO_STATUS_DRIVER            2
#define VIRTIO_STATUS_FAILED            128
#define VIRTIO_STATUS_FEATURES_OK       8
#define VIRTIO_STATUS_DRIVER_OK         4

/* 设备 ID */
#define VIRTIO_DEV_ID_BLOCK             2

/* virtio-blk 配置空间偏移 */
#define VIRTIO_BLK_CFG_CAPACITY         0x000

/* virtqueue 描述符标志 */
#define VIRTQ_DESC_F_NEXT               1
#define VIRTQ_DESC_F_WRITE              2

/* virtqueue 描述符 */
typedef struct {
    uint64_t addr;
    uint32_t len;
    uint16_t flags;
    uint16_t next;
} virtq_desc_t;

/* virtqueue available ring */
typedef struct {
    uint16_t flags;
    uint16_t idx;
    uint16_t ring[];
    /* 后面跟 used_event (如果协商了 VIRTIO_F_EVENT_IDX) */
} virtq_avail_t;

/* virtqueue used ring 元素 */
typedef struct {
    uint32_t id;
    uint32_t len;
} virtq_used_elem_t;

/* virtqueue used ring */
typedef struct {
    uint16_t flags;
    uint16_t idx;
    virtq_used_elem_t ring[];
} virtq_used_t;

/* virtio-blk 请求头 */
typedef struct {
    uint32_t type;
    uint32_t reserved;
    uint64_t sector;
} virtio_blk_req_hdr_t;

/* virtio-blk 请求类型 */
#define VIRTIO_BLK_T_IN                0  /* 读 */
#define VIRTIO_BLK_T_OUT               1  /* 写 */

/* 全局设备表 */
static virtio_blk_dev_t g_devices[VIRTIO_BLK_MAX_DEVICES];
static int g_device_count = 0;

/* 队列大小 */
#define VIRTQ_SIZE 64

/* --- 寄存器读写辅助函数 --- */

static inline uint32_t mmio_read32(uintptr_t base, int offset) {
    return *(volatile uint32_t *)(base + offset);
}

static inline void mmio_write32(uintptr_t base, int offset, uint32_t val) {
    *(volatile uint32_t *)(base + offset) = val;
}

/* --- 设备初始化 --- */

static int virtio_blk_init_one(uintptr_t mmio_base) {
    /* 检查 magic value */
    uint32_t magic = mmio_read32(mmio_base, VIRTIO_MMIO_MAGIC_VALUE);
    if (magic != 0x74726976) { /* "virt" */
        return 0;
    }

    uint32_t version = mmio_read32(mmio_base, VIRTIO_MMIO_VERSION);
    if (version != 1 && version != 2) { /* legacy: 1, modern: 2 */
        /* 都接受 */
    }

    uint32_t device_id = mmio_read32(mmio_base, VIRTIO_MMIO_DEVICE_ID);
    if (device_id != VIRTIO_DEV_ID_BLOCK) {
        return 0; /* 不是块设备 */
    }

    printf("[virtio-blk] 发现块设备 @ 0x%x, DeviceID=%d, Version=%d\n",
           (unsigned)mmio_base, device_id, version);

    /* --- 步骤 1: 复位设备 --- */
    mmio_write32(mmio_base, VIRTIO_MMIO_STATUS, 0);

    /* --- 步骤 2: ACKNOWLEDGE --- */
    mmio_write32(mmio_base, VIRTIO_MMIO_STATUS,
                 mmio_read32(mmio_base, VIRTIO_MMIO_STATUS) | VIRTIO_STATUS_ACKNOWLEDGE);

    /* --- 步骤 3: DRIVER --- */
    mmio_write32(mmio_base, VIRTIO_MMIO_STATUS,
                 mmio_read32(mmio_base, VIRTIO_MMIO_STATUS) | VIRTIO_STATUS_DRIVER);

    /* --- 步骤 4: 特性协商 (跳过, 使用默认特性) --- */

    /* --- 步骤 5: FEATURES_OK --- */
    mmio_write32(mmio_base, VIRTIO_MMIO_STATUS,
                 mmio_read32(mmio_base, VIRTIO_MMIO_STATUS) | VIRTIO_STATUS_FEATURES_OK);

    if ((mmio_read32(mmio_base, VIRTIO_MMIO_STATUS) & VIRTIO_STATUS_FEATURES_OK) == 0) {
        printf("[virtio-blk] 特性协商失败!\n");
        mmio_write32(mmio_base, VIRTIO_MMIO_STATUS,
                     mmio_read32(mmio_base, VIRTIO_MMIO_STATUS) | VIRTIO_STATUS_FAILED);
        return 0;
    }

    /* --- 步骤 6: 设备配置 --- */
    /* 选择队列 0 */
    mmio_write32(mmio_base, VIRTIO_MMIO_QUEUE_SEL, 0);

    uint32_t queue_max = mmio_read32(mmio_base, VIRTIO_MMIO_QUEUE_NUM_MAX);
    uint32_t queue_num = (queue_max < VIRTQ_SIZE) ? queue_max : VIRTQ_SIZE;
    if (queue_num == 0) queue_num = 1;

    mmio_write32(mmio_base, VIRTIO_MMIO_QUEUE_NUM, queue_num);

    /* 分配 virtqueue 内存 */
    size_t desc_size = 16 * queue_num;  /* 每个描述符 16 字节 */
    size_t avail_size = 6 + 2 * queue_num; /* flags + idx + ring + used_event */
    size_t used_size = 6 + 8 * queue_num;  /* flags + idx + ring */
    size_t total_size = ALIGN_UP(desc_size + avail_size + used_size, PAGE_SIZE);

    uint8_t *vq_mem = (uint8_t *)alloc_pages(total_size / PAGE_SIZE);
    if (!vq_mem) {
        printf("[virtio-blk] 内存分配失败!\n");
        return 0;
    }
    memset(vq_mem, 0, total_size);

    virtq_desc_t *desc = (virtq_desc_t *)vq_mem;
    virtq_avail_t *avail = (virtq_avail_t *)(vq_mem + desc_size);
    virtq_used_t *used = (virtq_used_t *)(vq_mem + desc_size + avail_size);

    /* 设置对齐和队列PFN (legacy) */
    mmio_write32(mmio_base, VIRTIO_MMIO_GUEST_PAGE_SIZE, PAGE_SIZE);
    mmio_write32(mmio_base, VIRTIO_MMIO_QUEUE_ALIGN, PAGE_SIZE);
    mmio_write32(mmio_base, VIRTIO_MMIO_QUEUE_PFN,
                 (uint32_t)((uintptr_t)vq_mem / PAGE_SIZE));

    /* 分配 IO 缓冲区 */
    uint8_t *io_buf = (uint8_t *)alloc_pages(2); /* 8KB IO 缓冲 */
    if (!io_buf) {
        printf("[virtio-blk] IO 缓冲区分配失败!\n");
        free_pages(vq_mem, total_size / PAGE_SIZE);
        return 0;
    }

    /* --- 步骤 7: DRIVER_OK --- */
    mmio_write32(mmio_base, VIRTIO_MMIO_STATUS,
                 mmio_read32(mmio_base, VIRTIO_MMIO_STATUS) | VIRTIO_STATUS_DRIVER_OK);

