/* --- IO 操作 --- */

static int virtio_blk_do_request(virtio_blk_dev_t *dev, uint64_t sector,
                                  void *buf, uint32_t num_sectors, int is_write)
{
    if (!dev || !dev->initialized) return -1;
    if (num_sectors == 0) return 0;

    uint32_t bytes = num_sectors * VIRTIO_BLK_SECTOR_SIZE;
    /* 检查: header(16) + data(bytes) + status(1) < io_buf_len */
    if (bytes + 17 > dev->io_buf_len) return -1;

    uintptr_t mmio = dev->mmio_base;
    uint32_t qnum = dev->queue_num;

    /* 获取描述符表 */
    virtq_desc_t *desc = (virtq_desc_t *)dev->desc;
    virtq_avail_t *avail = (virtq_avail_t *)dev->avail;
    virtq_used_t *used = (virtq_used_t *)dev->used;

    uint16_t desc_idx0 = dev->queue_idx % qnum;
    uint16_t desc_idx1 = (desc_idx0 + 1) % qnum;
    uint16_t desc_idx2 = (desc_idx0 + 2) % qnum;

    /* 设置请求头 (在 IO 缓冲区开头) */
    virtio_blk_req_hdr_t *hdr = (virtio_blk_req_hdr_t *)dev->io_buf;
    hdr->type = is_write ? VIRTIO_BLK_T_OUT : VIRTIO_BLK_T_IN;
    hdr->reserved = 0;
    hdr->sector = sector;

    /* 数据缓冲区紧接在请求头后面 */
    uint8_t *data_buf = dev->io_buf + sizeof(virtio_blk_req_hdr_t);

    /* 对于写操作, 先复制数据到 IO 缓冲区 (在头之后) */
    if (is_write) {
        memcpy(data_buf, buf, bytes);
    }

    /* 描述符 0: 请求头 (设备读) */
    desc[desc_idx0].addr = (uint64_t)(uintptr_t)hdr;
    desc[desc_idx0].len = sizeof(virtio_blk_req_hdr_t);
    desc[desc_idx0].flags = VIRTQ_DESC_F_NEXT;
    desc[desc_idx0].next = desc_idx1;

    /* 描述符 1: 数据缓冲区 */
    uint8_t *data_buf = dev->io_buf + sizeof(virtio_blk_req_hdr_t);
    desc[desc_idx1].addr = (uint64_t)(uintptr_t)data_buf;
    desc[desc_idx1].len = bytes;
    desc[desc_idx1].flags = VIRTQ_DESC_F_NEXT;
    if (is_write) {
        /* 写: 设备读数据 */
        desc[desc_idx1].flags = VIRTQ_DESC_F_NEXT;
    } else {
        /* 读: 设备写数据 */
        desc[desc_idx1].flags = VIRTQ_DESC_F_NEXT | VIRTQ_DESC_F_WRITE;
    }
    desc[desc_idx1].next = desc_idx2;

    /* 描述符 2: 状态字节 (设备写) */
    uint8_t *status = data_buf + bytes;
    desc[desc_idx2].addr = (uint64_t)(uintptr_t)status;
    desc[desc_idx2].len = 1;
    desc[desc_idx2].flags = VIRTQ_DESC_F_WRITE;
    desc[desc_idx2].next = 0;

    /* 发布到 available ring */
    avail->ring[avail->idx % qnum] = desc_idx0;

    /* 确保描述符和 available ring 对设备可见 */
    __asm__ __volatile__("fence w,w" ::: "memory");

    avail->idx++;

    /* 通知设备 */
    mmio_write32(mmio, VIRTIO_MMIO_QUEUE_NOTIFY, 0);

    /* 等待设备完成 */
    uint16_t used_idx = used->idx;

    /* 忙等 (简化实现) */
    while (used->idx == used_idx) {
        __asm__ __volatile__("fence r,r" ::: "memory");
    }

    /* 确保看到 used ring 更新 */
    __asm__ __volatile__("fence r,r" ::: "memory");

    /* 检查状态 */
    if (*status != 0) {
        printf("[virtio-blk] IO 错误: status=%d, sector=%d\n", *status, (unsigned)sector);
        return -1;
    }

    /* 如果是读操作, 复制数据到用户缓冲区 */
    if (!is_write) {
        memcpy(buf, data_buf, bytes);
    }

    dev->queue_idx = (dev->queue_idx + 3) % qnum;
    dev->last_avail_idx = avail->idx;

    return (int)bytes;
}

int virtio_blk_read(virtio_blk_dev_t *dev, uint64_t sector,
                    void *buf, uint32_t num_sectors) {
    return virtio_blk_do_request(dev, sector, buf, num_sectors, 0);
}

int virtio_blk_write(virtio_blk_dev_t *dev, uint64_t sector,
                     const void *buf, uint32_t num_sectors) {
    return virtio_blk_do_request(dev, sector, (void *)buf, num_sectors, 1);
}

void virtio_blk_info(virtio_blk_dev_t *dev) {
    if (!dev || !dev->initialized) {
        printf("[virtio-blk] 设备未初始化\n");
        return;
    }
    uint64_t mb = dev->capacity / 2048;
    printf("[virtio-blk] 设备 @ MMIO=0x%x, 容量=%d MB (%d 扇区)\n",
           (unsigned)dev->mmio_base, (unsigned)mb, (unsigned)dev->capacity);
}

