/* 获取指定 group 的 inode table 位置 */
static uint64_t get_inode_table_block(ext4_fs_t *fs, uint32_t group) {
    uint8_t gdt_buf[4096];
    if (read_gdt(fs, group, gdt_buf) < 0) return 0;

    uint32_t desc_per_block = fs->block_size / fs->desc_size;
    uint32_t offset_in_block = (group % desc_per_block) * fs->desc_size;

    if (fs->desc_size >= 64) {
        ext4_bg_desc_64_t *desc = (ext4_bg_desc_64_t *)(gdt_buf + offset_in_block);
        return le32(desc->bg_inode_table_lo) |
               ((uint64_t)le32(desc->bg_inode_table_hi) << 32);
    } else {
        ext4_bg_desc_32_t *desc = (ext4_bg_desc_32_t *)(gdt_buf + offset_in_block);
        return le32(desc->bg_inode_table_lo);
    }
}

/* 读取一个 inode */
static int read_inode(ext4_fs_t *fs, uint32_t inode_no, ext4_inode_t *ino) {
    if (inode_no == 0) return -1;

    uint32_t group = (inode_no - 1) / fs->inodes_per_group;
    uint32_t index = (inode_no - 1) % fs->inodes_per_group;

    uint64_t table_block = get_inode_table_block(fs, group);
    if (table_block == 0) return -1;

    uint64_t block_offset = index * fs->inode_size;
    uint64_t target_block = table_block + (block_offset / fs->block_size);
    uint32_t offset_in_block = block_offset % fs->block_size;

    uint8_t *block_buf = (uint8_t *)kmalloc(fs->block_size);
    if (!block_buf) return -1;

    if (read_block(fs, target_block, block_buf) < 0) {
        kfree(block_buf);
        return -1;
    }

    memcpy(ino, block_buf + offset_in_block,
           fs->inode_size < sizeof(ext4_inode_t) ? fs->inode_size : sizeof(ext4_inode_t));
    kfree(block_buf);
    return 0;
}

/* 解析区段树，将逻辑块号映射到物理块号 */
static int extent_map_logical_to_physical(ext4_fs_t *fs, ext4_inode_t *ino,
                                           uint64_t logical_block,
                                           uint64_t *physical_block)
{
    /* i_block 区段树头部 */
    ext4_extent_header_t *eh = (ext4_extent_header_t *)ino->i_block_u32;

    if (le16(eh->eh_magic) != EXT4_EXTENT_MAGIC) {
        return -1; /* 不是区段树 */
    }

    uint16_t depth = le16(eh->eh_depth);
    uint16_t entries = le16(eh->eh_entries);
    uint16_t max_entries = le16(eh->eh_max);

    /* 分配缓冲区读取区段节点 */
    uint8_t *node_buf = (uint8_t *)kmalloc(fs->block_size);
    if (!node_buf) return -1;

    /* 从根节点开始复制 */
    memcpy(node_buf, eh, 60); /* i_block 是 60 字节 */

    /* 遍历到叶节点 */
    while (depth > 0) {
        ext4_extent_header_t *cur_eh = (ext4_extent_header_t *)node_buf;
        entries = le16(cur_eh->eh_entries);

        /* 在索引节点中找到正确的子节点 */
        ext4_extent_idx_t *idx = (ext4_extent_idx_t *)(node_buf + sizeof(ext4_extent_header_t));
        int found = 0;

        for (int i = entries - 1; i >= 0; i--) {
            if (le32(idx[i].ei_block) <= logical_block) {
                uint64_t child_block = le32(idx[i].ei_leaf_lo) |
                                      ((uint64_t)le32(idx[i].ei_leaf_hi) << 32);
                if (read_block(fs, child_block, node_buf) < 0) {
                    kfree(node_buf);
                    return -1;
                }
                found = 1;
                break;
            }
        }

        if (!found) {
            kfree(node_buf);
            return -1;
        }
        depth--;
    }

    /* 在叶节点中查找物理块 */
    ext4_extent_header_t *leaf_eh = (ext4_extent_header_t *)node_buf;
    entries = le16(leaf_eh->eh_entries);
    ext4_extent_t *ext = (ext4_extent_t *)(node_buf + sizeof(ext4_extent_header_t));

    for (int i = 0; i < entries; i++) {
        uint32_t ee_block = le32(ext[i].ee_block);
        uint16_t ee_len = le16(ext[i].ee_len);

        if (logical_block >= ee_block && logical_block < ee_block + ee_len) {
            uint64_t block_start = le32(ext[i].ee_start_lo) |
                                  ((uint64_t)le16(ext[i].ee_start_hi) << 32);
            *physical_block = block_start + (logical_block - ee_block);
            kfree(node_buf);
            return 0;
        }
    }

    kfree(node_buf);
    return -1; /* 未找到 */
}

/* 将文件内部的逻辑偏移映射到物理块号 */
static int file_map_block(ext4_fs_t *fs, ext4_inode_t *ino,
                           uint64_t file_offset, uint64_t *phys_block)
{
    uint64_t logical_block = file_offset / fs->block_size;

    /* 检查是否使用区段树 */
    if (le32(ino->i_flags) & EXT4_EXTENTS_FL) {
        return extent_map_logical_to_physical(fs, ino, logical_block, phys_block);
    }

    /* 回退到旧的直接/间接块映射 (ext2/ext3 兼容) */
    /* 直接块: i_block[0..11] */
    if (logical_block < 12) {
        *phys_block = le32(ino->i_block_u32[logical_block]);
        return 0;
    }

    /* 简单实现: 不支持间接块 */
    return -1;
}

