                    memcpy(entries[count].name, d->name, name_len);
                    entries[count].name[name_len] = '\0';
                } else {
                    memcpy(entries[count].name, d->name, 254);
                    entries[count].name[254] = '\0';
                }
                count++;
            }

            uint16_t rec_len = le16(d->rec_len);
            if (rec_len == 0) break;

