int ext4_lookup(ext4_fs_t *fs, uint32_t dir_inode,
                const char *name, uint32_t *out_inode, uint8_t *out_type)
{
    ext4_dir_entry_t entries[256];
    int count = ext4_readdir(fs, dir_inode, entries, 256);

    for (int i = 0; i < count; i++) {
        if (strcmp(entries[i].name, name) == 0) {
            if (out_inode) *out_inode = entries[i].inode;
            if (out_type) *out_type = entries[i].file_type;
            return 0;
        }
    }
    return -1;
}

int ext4_open(ext4_fs_t *fs, uint32_t inode) {
    if (!fs->initialized) return -1;

    /* 找空闲 fd */
    int fd = -1;
    for (int i = 0; i < EXT4_MAX_OPEN_FILES; i++) {
        if (fs->open_files[i].inode == 0) {
            fd = i;
            break;
        }
    }
    if (fd < 0) return -1;

    /* 读取 inode 获取文件大小 */
    ext4_inode_t ino;
    if (read_inode(fs, inode, &ino) < 0) return -1;

    uint64_t size = le32(ino.i_size_lo);
    /* TODO: 处理 64-bit 大小 */

    fs->open_files[fd].inode = inode;
    fs->open_files[fd].size = size;
    fs->open_files[fd].pos = 0;
    fs->open_files[fd].cache_block = (uint8_t *)kmalloc(fs->block_size);
    fs->open_files[fd].cache_block_no = (uint64_t)-1;

    if (!fs->open_files[fd].cache_block) {
        fs->open_files[fd].inode = 0;
        return -1;
    }

    return fd;
}

int ext4_close(ext4_fs_t *fs, int fd) {
    if (fd < 0 || fd >= EXT4_MAX_OPEN_FILES) return -1;
    if (fs->open_files[fd].inode == 0) return -1;

    if (fs->open_files[fd].cache_block) {
        kfree(fs->open_files[fd].cache_block);
    }
    memset(&fs->open_files[fd], 0, sizeof(fs->open_files[fd]));
    return 0;
}

int ext4_read(ext4_fs_t *fs, int fd, void *buf, uint32_t len) {
    if (fd < 0 || fd >= EXT4_MAX_OPEN_FILES) return -1;
    if (fs->open_files[fd].inode == 0) return -1;

    ext4_inode_t ino;
    if (read_inode(fs, fs->open_files[fd].inode, &ino) < 0) return -1;

    uint64_t remaining = fs->open_files[fd].size - fs->open_files[fd].pos;
    if (len > remaining) len = (uint32_t)remaining;
    if (len == 0) return 0;

    uint8_t *dst = (uint8_t *)buf;
    uint32_t bytes_read = 0;

    while (bytes_read < len) {
        uint64_t file_offset = fs->open_files[fd].pos + bytes_read;
        uint64_t phys_block;

        if (file_map_block(fs, &ino, file_offset, &phys_block) < 0) {
            /* 稀疏文件: 填充零 */
            uint32_t block_remaining = fs->block_size - (file_offset % fs->block_size);
            uint32_t to_fill = len - bytes_read;
            if (to_fill > block_remaining) to_fill = block_remaining;
            memset(dst + bytes_read, 0, to_fill);
            bytes_read += to_fill;
            continue;
        }

        /* 检查缓存 */
        if (phys_block != fs->open_files[fd].cache_block_no) {
            if (read_block(fs, phys_block,
                           fs->open_files[fd].cache_block) < 0) {
                break;
            }
            fs->open_files[fd].cache_block_no = phys_block;
        }

        uint32_t block_offset = file_offset % fs->block_size;
        uint32_t block_remaining = fs->block_size - block_offset;
        uint32_t to_copy = len - bytes_read;
        if (to_copy > block_remaining) to_copy = block_remaining;

        memcpy(dst + bytes_read,
               fs->open_files[fd].cache_block + block_offset,
               to_copy);
        bytes_read += to_copy;
    }

    fs->open_files[fd].pos += bytes_read;
    return (int)bytes_read;
}

uint64_t ext4_file_size(ext4_fs_t *fs, int fd) {
    if (fd < 0 || fd >= EXT4_MAX_OPEN_FILES) return 0;
    if (fs->open_files[fd].inode == 0) return 0;
    return fs->open_files[fd].size;
}

int ext4_is_regular(ext4_fs_t *fs, uint32_t inode) {
    ext4_inode_t ino;
    if (read_inode(fs, inode, &ino) < 0) return 0;
    return (le16(ino.i_mode) & S_IFMT) == S_IFREG;
}

uint64_t ext4_get_size(ext4_fs_t *fs, uint32_t inode) {
    ext4_inode_t ino;
    if (read_inode(fs, inode, &ino) < 0) return 0;
    return le32(ino.i_size_lo);
}

int ext4_find_by_suffix(ext4_fs_t *fs, const char *suffix,
                        uint32_t *inodes, int max)
{
    ext4_dir_entry_t entries[256];
    int count = ext4_readdir(fs, EXT4_ROOT_INO, entries, 256);
    int found = 0;

    for (int i = 0; i < count && found < max; i++) {
        if (str_endswith(entries[i].name, suffix)) {
            inodes[found++] = entries[i].inode;
        }
    }
    return found;
}

void ext4_print_info(ext4_fs_t *fs) {
    if (!fs->initialized) {
        printf("[ext4] 文件系统未挂载\n");
        return;
    }
    printf("[ext4] 块大小: %d 字节\n", fs->block_size);
    printf("[ext4] inode 大小: %d 字节\n", fs->inode_size);
    printf("[ext4] 总块数: %d\n", (unsigned)fs->total_blocks);
    printf("[ext4] 总 inode 数: %d\n", (unsigned)fs->total_inodes);
    printf("[ext4] 块组数: %d\n", fs->block_groups);
    printf("[ext4] 每块组块数: %d\n", fs->blocks_per_group);
    printf("[ext4] 描述符大小: %d\n", fs->desc_size);
}

/* 进程管理和页表实现 */

#include "proc.h"
#include "alloc.h"
#include "string.h"
#include "printf.h"

/* 全局进程表 */
static process_t g_proc_table[MAX_PROCS];
static int g_current_pid = -1;
process_t *g_current_proc = NULL;

/* 内核上下文保存区 (全局, 供汇编 trap_entry.S 访问) */
kernel_context_t g_kernel_ctx;

/* 内核页表根 (identity mapping) */
static uintptr_t g_kernel_page_table = 0;

/* 链接器导出的符号 */
extern uint8_t _kernel_start[];
extern uint8_t _kernel_end[];
extern uint8_t _user_memory_start[];

/* 汇编 trampoline: 保存内核上下文并进入用户态
 * 声明: void _enter_user_trampoline(uintptr_t entry, uintptr_t user_sp,
 *                                    uintptr_t satp_val, kernel_context_t *ctx)
 * 此函数:
 *   1. 保存 ra, sp 到 ctx
 *   2. 切换页表 (satp)
 *   3. 设置 sscratch = sp (内核 sp)
 *   4. sret 到用户态
 *   5. (用户进程 exit 后) 返回到调用者
 */
extern void _enter_user_trampoline(uintptr_t entry, uintptr_t user_sp,
                                    uintptr_t satp_val, kernel_context_t *ctx);

/* 链接脚本符号: 内核结束后的页 */
extern uint8_t _heap_start[];

kernel_context_t *get_kernel_context(void) {
    return &g_kernel_ctx;
}

void save_kernel_context(kernel_context_t *ctx) {
    ctx->satp = get_kernel_satp();
    /* sp 和 ra 由 trampoline 保存 */
}

/* ============================================================
 * 物理页分配器
 * ============================================================ */

static uint8_t *next_free_page = NULL;

void paging_init(void) {
    /* 从 BSS 之后分配物理页 */
    next_free_page = (uint8_t *)ALIGN_UP((uintptr_t)&_kernel_end, PAGE_SIZE);

    printf("[paging] 物理页从 0x%x 开始, 用户空间起始 0x%x\n",
           (unsigned)(uintptr_t)next_free_page,
           (unsigned)(uintptr_t)_user_memory_start);
}

uintptr_t alloc_page_table(void) {
    uint8_t *page = next_free_page;
    next_free_page += PAGE_SIZE;
    memset(page, 0, PAGE_SIZE);
    return (uintptr_t)page;
}

uintptr_t get_kernel_satp(void) {
#ifdef __riscv
    uintptr_t satp;
    __asm__ __volatile__("csrr %0, satp" : "=r"(satp));
    return satp;
#else
    return 0;
#endif
}

/* ============================================================
 * Sv39 页表操作 (RISC-V)
 * ============================================================ */

#ifdef __riscv

#define VPN2(va) (((va) >> 30) & 0x1FF)
#define VPN1(va) (((va) >> 21) & 0x1FF)
#define VPN0(va) (((va) >> 12) & 0x1FF)

static inline uint64_t make_pte(uintptr_t ppn, uint64_t flags) {
    return ((ppn >> 12) << PTE_PFN_SHIFT) | flags;
}

static inline uintptr_t pte_to_ppn(uint64_t pte) {
    return (uintptr_t)((pte & PTE_PPN_MASK) >> PTE_PFN_SHIFT) << 12;
}

int map_page(uintptr_t root_ppn, uintptr_t vaddr,
             uintptr_t paddr, uint64_t flags)
{
    uint64_t *l2 = (uint64_t *)root_ppn;
    uint64_t *l1, *l0;

    int i2 = VPN2(vaddr);
    int i1 = VPN1(vaddr);
    int i0 = VPN0(vaddr);

    if (!(l2[i2] & PTE_V)) {
        uintptr_t l1_page = alloc_page_table();
        if (!l1_page) return -1;
        l2[i2] = make_pte(l1_page, PTE_V);
    }
    l1 = (uint64_t *)pte_to_ppn(l2[i2]);

    if (!(l1[i1] & PTE_V)) {
        uintptr_t l0_page = alloc_page_table();
        if (!l0_page) return -1;
        l1[i1] = make_pte(l0_page, PTE_V);
    }
    l0 = (uint64_t *)pte_to_ppn(l1[i1]);

    l0[i0] = make_pte(paddr, flags);

    __asm__ __volatile__("sfence.vma zero, %0" :: "r"(vaddr) : "memory");
    return 0;
}

void unmap_page(uintptr_t root_ppn, uintptr_t vaddr) {
    uint64_t *l2 = (uint64_t *)root_ppn;
    int i2 = VPN2(vaddr);
    if (!(l2[i2] & PTE_V)) return;
    uint64_t *l1 = (uint64_t *)pte_to_ppn(l2[i2]);
    int i1 = VPN1(vaddr);
    if (!(l1[i1] & PTE_V)) return;
    uint64_t *l0 = (uint64_t *)pte_to_ppn(l1[i1]);
    int i0 = VPN0(vaddr);
    l0[i0] = 0;
    __asm__ __volatile__("sfence.vma zero, %0" :: "r"(vaddr) : "memory");
}

uintptr_t walk_page(uintptr_t root_ppn, uintptr_t vaddr) {
    uint64_t *l2 = (uint64_t *)root_ppn;
    int i2 = VPN2(vaddr);
    if (!(l2[i2] & PTE_V)) return 0;
    uint64_t *l1 = (uint64_t *)pte_to_ppn(l2[i2]);
    int i1 = VPN1(vaddr);
    if (!(l1[i1] & PTE_V)) return 0;
    uint64_t *l0 = (uint64_t *)pte_to_ppn(l1[i1]);
    int i0 = VPN0(vaddr);
    if (!(l0[i0] & PTE_V)) return 0;
    return pte_to_ppn(l0[i0]) | (vaddr & 0xFFF);
}

void switch_page_table(uintptr_t root_ppn) {
    uint64_t satp_val = (8UL << 60) | ((uint64_t)root_ppn >> 12);
    __asm__ __volatile__("csrw satp, %0" :: "r"(satp_val) : "memory");
    __asm__ __volatile__("sfence.vma" ::: "memory");
}

/* ============================================================
 * 进入用户态 (关键函数)
 *
 * enter_user_process() 使用汇编 trampoline:
 *   _enter_user_trampoline(entry, user_sp, satp_val, &g_kernel_ctx)
 *
 * trampoline 保存内核 ra/sp, 切换页表, sret 到用户态.
 * 用户态进程 exit 后, trap_entry.S 检测到 g_return_to_kernel=1,
 * 使用保存的 ra/sp 返回到 trampoline, trampoline 再返回到此函数.
 * ============================================================ */

int enter_user_process(uintptr_t entry, uintptr_t user_stack,
                       uintptr_t page_table_root)
{
    kernel_context_t *ctx = &g_kernel_ctx;

    /* 保存 satp */
    ctx->satp = get_kernel_satp();
    ctx->trap_frame_addr = 0;

    /* 计算用户页表的 satp 值 */
    uint64_t user_satp = (8UL << 60) | ((uint64_t)page_table_root >> 12);

    /* 调用汇编 trampoline:
     *   - 保存 ra (返回到这里的地址) 和 sp 到 ctx
     *   - 切换页表到 user_satp
     *   - sret 到用户态 entry
     *   - (用户进程 exit 后) 恢复内核 sp, 返回到这里
     */
    _enter_user_trampoline(entry, user_stack, user_satp, ctx);

    /* ============================================
     * 用户进程已退出, 执行到达这里
     * 返回退出码
     * ============================================ */

    if (g_current_proc) {
        return (int)g_current_proc->exit_code;
    }
    return 0;
}

#endif /* __riscv */

