/* ============================================================
 * 进程管理
 * ============================================================ */

void proc_init(void) {
    memset(g_proc_table, 0, sizeof(g_proc_table));
    memset(&g_kernel_ctx, 0, sizeof(g_kernel_ctx));
    g_current_pid = -1;
    g_current_proc = NULL;

    paging_init();
    g_kernel_page_table = get_kernel_satp();

    printf("[proc] 进程管理器初始化完成\n");
}

int proc_get_free_pid(void) {
    for (int i = 0; i < MAX_PROCS; i++) {
        if (g_proc_table[i].state == PROC_STATE_FREE) return i;
    }
    return -1;
}

int proc_create(uintptr_t entry, uintptr_t page_table_root) {
    int pid = proc_get_free_pid();
    if (pid < 0) return -1;

    process_t *proc = &g_proc_table[pid];
    memset(proc, 0, sizeof(*proc));

    proc->pid = pid;
    proc->state = PROC_STATE_READY;
    proc->page_table = page_table_root;
    proc->entry_point = entry;
    proc->user_stack = USER_STACK_TOP;
    proc->exit_code = 0;
    proc->trap_frame = NULL;

    for (int i = 0; i < 16; i++) proc->fd_table[i] = -1;

    return pid;
}

void proc_destroy(int pid) {
    if (pid < 0 || pid >= MAX_PROCS) return;
    process_t *proc = &g_proc_table[pid];

    for (int i = 0; i < 16; i++) {
        if (proc->fd_table[i] >= 0) {
            proc->fd_table[i] = -1;
        }
    }

    proc->state = PROC_STATE_FREE;
    proc->trap_frame = NULL;
}

process_t *proc_get(int pid) {
    if (pid < 0 || pid >= MAX_PROCS) return NULL;
    if (g_proc_table[pid].state == PROC_STATE_FREE) return NULL;
    return &g_proc_table[pid];
}

process_t *proc_get_current(void) {
    return g_current_proc;
}

void proc_set_current(int pid) {
    g_current_pid = pid;
    g_current_proc = proc_get(pid);
}

