/* 系统调用处理和 trap 分发 */

#include "syscall.h"
#include "proc.h"
#include "printf.h"
#include "string.h"
#include "ext4.h"
#include "alloc.h"

/* 外部引用 */
extern ext4_fs_t g_ext4_fs;

/* 内核返回标志 (在 trap_entry.S 中定义) */
extern int g_return_to_kernel;
extern uintptr_t g_kernel_return_sp;
extern uintptr_t g_kernel_return_ra;

/* 当前进程 */
extern process_t *g_current_proc;

/* 陷阱原因 */
#define SCAUSE_ECALL_U  8

void syscall_init(void) {
    printf("[syscall] 系统调用初始化完成\n");
}

/* --- 系统调用实现 --- */

static int64_t sys_write(int fd, const void *buf, uint64_t count) {
    if (fd == STDOUT_FILENO || fd == STDERR_FILENO) {
        const char *str = (const char *)buf;
        for (uint64_t i = 0; i < count; i++) {
            putchar(str[i]);
        }
        return (int64_t)count;
    }

    /* 文件写入 - 暂不支持 */
    return -1;
}

static int64_t sys_read(int fd, void *buf, uint64_t count) {
    if (fd == STDIN_FILENO) {
        return 0; /* 无输入 */
    }

    if (g_current_proc && fd >= 0 && fd < 16) {
        int ext4_fd = g_current_proc->fd_table[fd];
        if (ext4_fd >= 0) {
            return ext4_read(&g_ext4_fs, ext4_fd, buf, (uint32_t)count);
        }
    }
    return -1;
}

static int64_t sys_openat(int dirfd, const char *pathname, int flags, int mode) {
    (void)dirfd; (void)flags; (void)mode;

    if (!g_current_proc) return -1;

    /* 需要从用户空间复制路径字符串 */
    /* 使用 walk_page 获取物理地址 */
    uintptr_t phys_addr = walk_page(g_current_proc->page_table,
                                     (uintptr_t)pathname);
    if (!phys_addr) {
        /* 内核直接访问 (简化) */
        phys_addr = (uintptr_t)pathname;
    }

    const char *path = (const char *)phys_addr;

    uint32_t inode;
    uint8_t type;
    if (ext4_lookup(&g_ext4_fs, EXT4_ROOT_INO, path, &inode, &type) < 0) {
        return -1; /* 文件未找到 */
    }

    int ext4_fd = ext4_open(&g_ext4_fs, inode);
    if (ext4_fd < 0) return -1;

    for (int i = 0; i < 16; i++) {
        if (g_current_proc->fd_table[i] < 0) {
            g_current_proc->fd_table[i] = ext4_fd;
            return i;
        }
    }

    ext4_close(&g_ext4_fs, ext4_fd);
    return -1;
}

static int64_t sys_close(int fd) {
    if (!g_current_proc) return -1;
    if (fd < 0 || fd >= 16) return -1;

    int ext4_fd = g_current_proc->fd_table[fd];
    if (ext4_fd >= 0) {
        ext4_close(&g_ext4_fs, ext4_fd);
        g_current_proc->fd_table[fd] = -1;
    }
    return 0;
}

static void sys_exit(int status) {
    kernel_context_t *ctx = get_kernel_context();

    if (g_current_proc) {
        g_current_proc->exit_code = status;
        g_current_proc->state = PROC_STATE_ZOMBIE;
    }

    printf("[syscall] 进程退出, 状态=%d\n", status);

    /* --- 关键: 设置返回内核的上下文 --- */

    /* 1. 恢复内核页表 */
    uintptr_t kernel_ppn = (ctx->satp & 0x0000FFFFFFFFFFFFUL) << 12;
    switch_page_table(kernel_ppn);

    /* 2. 通知 trap_entry.S 返回到内核
     * g_kernel_return_ra 和 g_kernel_return_sp 已由
     * _enter_user_trampoline 正确设置为 resume point 和内核 sp
     * 这里只需设置 g_return_to_kernel 标志 */
    g_return_to_kernel = 1;
}

static int64_t sys_brk(uintptr_t new_brk) {
    (void)new_brk;
    return 0; /* 简化: 始终成功 */
}

static int64_t sys_fstat(int fd, void *statbuf) {
    (void)fd;
    if (statbuf) {
        memset(statbuf, 0, 144);
    }
    return 0;
}

/* --- Trap 分发 --- */

void trap_handler(trap_frame_t *frame) {
    uint64_t scause = frame->scause;
    uint64_t sepc = frame->sepc;

    int is_interrupt = (scause >> 63) & 1;
    uint64_t cause_code = scause & 0x7FFFFFFFFFFFFFFFULL;

    if (is_interrupt) {
        /* 定时器等中断, 目前忽略 */
        return;
    }

    switch (cause_code) {
    case SCAUSE_ECALL_U: {
        int64_t ret = 0;
        uint64_t syscall_nr = frame->a7;

        switch (syscall_nr) {
        case SYS_write:
            ret = sys_write((int)frame->a0, (const void *)(uintptr_t)frame->a1,
                           frame->a2);
            break;
        case SYS_read:
            ret = sys_read((int)frame->a0, (void *)(uintptr_t)frame->a1,
                          frame->a2);
            break;
        case SYS_openat:
            ret = sys_openat((int)frame->a0, (const char *)(uintptr_t)frame->a1,
                            (int)frame->a2, (int)frame->a3);
            break;
        case SYS_close:
            ret = sys_close((int)frame->a0);
            break;
        case SYS_exit:
            sys_exit((int)frame->a0);
            /* sys_exit 设置了 g_return_to_kernel=1
             * trap_handler 返回后, trap_entry.S 会跳转到内核 */
            return; /* 不修改 frame->a0, 不增加 sepc */
        case SYS_brk:
            ret = sys_brk((uintptr_t)frame->a0);
            break;
        case SYS_fstat:
            ret = sys_fstat((int)frame->a0, (void *)(uintptr_t)frame->a1);
            break;
        case SYS_getdents64:
            ret = 0; /* 没有更多目录项 */
            break;
        default:
            printf("[syscall] 未知系统调用 nr=%d\n", (unsigned)syscall_nr);
            ret = -1;
            break;
        }

        frame->a0 = (uint64_t)ret;
        frame->sepc = sepc + 4; /* 跳过 ecall 指令 */
        break;
    }
    default:
        printf("[trap] 未处理异常: cause=0x%x, epc=0x%x\n",
               (unsigned)cause_code, (unsigned)sepc);
        frame->sepc = sepc + 4; /* 跳过出错的指令 */
        break;
    }
}

/* ELF 64-bit 程序加载器实现 */

#include "elf_loader.h"
#include "proc.h"
#include "alloc.h"
#include "string.h"
#include "printf.h"

/* ELF64 头 */
#define EI_NIDENT 16

typedef struct {
    uint8_t  e_ident[EI_NIDENT];
    uint16_t e_type;
    uint16_t e_machine;
    uint32_t e_version;
    uint64_t e_entry;
    uint64_t e_phoff;
    uint64_t e_shoff;
    uint32_t e_flags;
    uint16_t e_ehsize;
    uint16_t e_phentsize;
    uint16_t e_phnum;
    uint16_t e_shentsize;
    uint16_t e_shnum;
    uint16_t e_shstrndx;
} elf64_ehdr_t;

/* ELF64 程序头 */
typedef struct {
    uint32_t p_type;
    uint32_t p_flags;
    uint64_t p_offset;
    uint64_t p_vaddr;
    uint64_t p_paddr;
    uint64_t p_filesz;
    uint64_t p_memsz;
    uint64_t p_align;
} elf64_phdr_t;

/* 程序头类型 */
#define PT_NULL    0
#define PT_LOAD    1
#define PT_DYNAMIC 2
#define PT_INTERP  3
#define PT_NOTE    4

/* 程序头标志 */
#define PF_X        1
#define PF_W        2
#define PF_R        4

/* ELF ident 索引 */
#define EI_MAG0    0
#define EI_MAG1    1
#define EI_MAG2    2
#define EI_MAG3    3
#define EI_CLASS   4
#define EI_DATA    5
#define EI_VERSION 6

/* ELF 类 */
#define ELFCLASS64  2

/* 数据编码 */
#define ELFDATA2LSB 1  /* 小端 */

/* ELF 魔数 */
#define ELFMAG0     0x7F
#define ELFMAG1     'E'
#define ELFMAG2     'L'
#define ELFMAG3     'F'

/* ============================================================
 * ELF 加载器
 * ============================================================ */

static int verify_elf_header(const elf64_ehdr_t *ehdr) {
    if (ehdr->e_ident[EI_MAG0] != ELFMAG0 ||
        ehdr->e_ident[EI_MAG1] != ELFMAG1 ||
        ehdr->e_ident[EI_MAG2] != ELFMAG2 ||
        ehdr->e_ident[EI_MAG3] != ELFMAG3) {
        printf("[ELF] 无效的 ELF 魔数\n");
        return -1;
    }

    if (ehdr->e_ident[EI_CLASS] != ELFCLASS64) {
        printf("[ELF] 仅支持 64-bit ELF\n");
        return -1;
    }

    if (ehdr->e_ident[EI_DATA] != ELFDATA2LSB) {
        printf("[ELF] 仅支持小端格式\n");
        return -1;
    }

    return 0;
}

static elf_load_result_t elf_load_internal(const uint8_t *data, size_t size,
                                            uintptr_t load_base,
                                            int (*read_fn)(void *ctx, uint64_t offset,
                                                           void *buf, uint32_t len),
                                            void *read_ctx)
{
    elf_load_result_t result;
    memset(&result, 0, sizeof(result));
    result.success = 0;

    if (size < sizeof(elf64_ehdr_t)) {
        printf("[ELF] 文件太小\n");
        return result;
    }

    const elf64_ehdr_t *ehdr = (const elf64_ehdr_t *)data;
    if (verify_elf_header(ehdr) < 0) return result;

    printf("[ELF] 加载: entry=0x%x, phoff=%d, phnum=%d\n",
           (unsigned)ehdr->e_entry, (unsigned)ehdr->e_phoff,
           ehdr->e_phnum);

    /* 分配根页表 */
    uintptr_t page_table_root = alloc_page_table();
    if (!page_table_root) {
        printf("[ELF] 页表分配失败\n");
        return result;
    }

    /* 遍历程序头 */
    uint16_t phnum = ehdr->e_phnum;
    uint64_t phoff = ehdr->e_phoff;
    uint16_t phentsize = ehdr->e_phentsize;

    /* 分配缓冲区读取程序头 */
    size_t phdr_total = (size_t)phnum * phentsize;
    uint8_t *phdr_buf = NULL;

    if (read_fn) {
        phdr_buf = (uint8_t *)kmalloc(phdr_total);
        if (!phdr_buf) goto fail;
        if (read_fn(read_ctx, phoff, phdr_buf, (uint32_t)phdr_total) < 0) {
            kfree(phdr_buf);
            goto fail;
        }
    } else {
        if (phoff + phdr_total > size) goto fail;
        phdr_buf = (uint8_t *)(data + phoff);
    }

    uintptr_t min_vaddr = (uintptr_t)-1;
    uintptr_t max_vaddr = 0;

    for (int i = 0; i < phnum; i++) {
        elf64_phdr_t *phdr = (elf64_phdr_t *)(phdr_buf + i * phentsize);

        if (phdr->p_type != PT_LOAD) continue;
        if (phdr->p_memsz == 0) continue;

        uint64_t vaddr_start = phdr->p_vaddr;
        uint64_t vaddr_end = phdr->p_vaddr + phdr->p_memsz;
        uint64_t file_start = phdr->p_offset;
        uint64_t file_size = phdr->p_filesz;
        uint64_t mem_size = phdr->p_memsz;
        uint64_t p_flags = phdr->p_flags;

        /* 对齐 */
        uintptr_t page_start = ALIGN_DOWN(vaddr_start, PAGE_SIZE);
        uintptr_t page_end = ALIGN_UP(vaddr_end, PAGE_SIZE);

        if (page_start < min_vaddr) min_vaddr = page_start;
        if (page_end > max_vaddr) max_vaddr = page_end;

        /* 分配物理页并映射 */
        for (uintptr_t va = page_start; va < page_end; va += PAGE_SIZE) {
            /* 分配物理页 */
            uint8_t *phys_page = (uint8_t *)alloc_page();
            if (!phys_page) {
                printf("[ELF] 物理页分配失败 @ 0x%x\n", (unsigned)va);
                if (read_fn) kfree(phdr_buf);
                goto fail;
            }
            memset(phys_page, 0, PAGE_SIZE);

            /* 确定此页的权限 */
            uint64_t pte_flags = PTE_V | PTE_U | PTE_A | PTE_D;
            if (p_flags & PF_R) pte_flags |= PTE_R;
            if (p_flags & PF_W) pte_flags |= PTE_W;
            if (p_flags & PF_X) pte_flags |= PTE_X;
            if (!(p_flags & PF_X)) pte_flags |= PTE_R; /* 至少可读 */

            /* 映射此页 */
            if (map_page(page_table_root, va, (uintptr_t)phys_page, pte_flags) < 0) {
                printf("[ELF] 页面映射失败 @ 0x%x\n", (unsigned)va);
                free_page(phys_page);
                if (read_fn) kfree(phdr_buf);
                goto fail;
            }

            /* 如果在文件范围内，复制文件数据 */
            if (va < vaddr_start + file_size && va + PAGE_SIZE > vaddr_start) {
                uint32_t page_file_offset = 0;
                uint32_t page_copy_start = 0;
                uint32_t page_copy_end = PAGE_SIZE;

                if (va < vaddr_start) {
                    page_copy_start = (uint32_t)(vaddr_start - va);
                }
                if (va + PAGE_SIZE > vaddr_start + file_size) {
                    page_copy_end = (uint32_t)(vaddr_start + file_size - va);
                }

                uint64_t file_offset = file_start + (va - vaddr_start) + page_copy_start;
                uint32_t copy_len = page_copy_end - page_copy_start;

                if (copy_len > 0 && copy_len <= PAGE_SIZE) {
                    if (read_fn) {
                        read_fn(read_ctx, file_offset,
                                phys_page + page_copy_start, copy_len);
                    } else {
                        if (file_offset + copy_len <= size) {
                            memcpy(phys_page + page_copy_start,
                                   data + file_offset, copy_len);
                        }
                    }
                }
            }
        }
    }

    if (read_fn && phdr_buf) {
        kfree(phdr_buf);
    }

    /* 设置用户栈 */
    if (elf_setup_stack(page_table_root, USER_STACK_TOP, 0, NULL, NULL) < 0) {
        printf("[ELF] 用户栈设置失败\n");
        goto fail;
    }

    result.entry_point = ehdr->e_entry;
    result.page_table_root = page_table_root;
    result.success = 1;

    printf("[ELF] 加载成功! entry=0x%x, pgtable=0x%x\n",
           (unsigned)result.entry_point, (unsigned)result.page_table_root);
    return result;

fail:
    result.success = 0;
    result.entry_point = 0;
    result.page_table_root = 0;
    return result;
}

