/* 基于文件的读取回调上下文 */
typedef struct {
    ext4_fs_t *fs;
    int        fd;
} file_read_ctx_t;

static int file_read_cb(void *ctx, uint64_t offset, void *buf, uint32_t len) {
    file_read_ctx_t *fctx = (file_read_ctx_t *)ctx;
    /* seek 是通过设置 fd 的 pos 来实现的... 但我们不能 seek */

    /* 重新打开文件并读取到偏移 */
    /* 简化: 读取整个文件到内存，然后按偏移复制 */

    ext4_fs_t *fs = fctx->fs;
    uint32_t inode = fs->open_files[fctx->fd].inode;

    ext4_close(fs, fctx->fd);
    int new_fd = ext4_open(fs, inode);
    if (new_fd < 0) return -1;

    /* 手动推进 read 位置 */
    uint8_t *skip_buf = (uint8_t *)kmalloc(4096);
    if (!skip_buf) { ext4_close(fs, new_fd); return -1; }

    uint64_t remaining = offset;
    while (remaining > 0) {
        uint32_t to_read = (uint32_t)(remaining > 4096 ? 4096 : remaining);
        if (ext4_read(fs, new_fd, skip_buf, to_read) < 0) break;
        remaining -= to_read;
    }

    int ret = ext4_read(fs, new_fd, buf, len);

    kfree(skip_buf);

    /* 恢复 fd */
    fctx->fd = new_fd;
    return ret;
}

elf_load_result_t elf_load(ext4_fs_t *fs, uint32_t inode, uintptr_t load_base) {
    elf_load_result_t result;
    memset(&result, 0, sizeof(result));

    /* 先读取 ELF 头 */
    int fd = ext4_open(fs, inode);
    if (fd < 0) {
        printf("[ELF] 无法打开文件 inode=%d\n", inode);
        return result;
    }

    elf64_ehdr_t ehdr;
    if (ext4_read(fs, fd, &ehdr, sizeof(ehdr)) < (int)sizeof(ehdr)) {
        printf("[ELF] 读取 ELF 头失败\n");
        ext4_close(fs, fd);
        return result;
    }

    uint64_t file_size = ext4_file_size(fs, fd);
    ext4_close(fs, fd);

    /* 将整个 ELF 文件读入内存 (简化实现) */
    uint8_t *elf_data = (uint8_t *)kmalloc((size_t)file_size + 4096);
    if (!elf_data) {
        printf("[ELF] 无法分配 %d 字节用于 ELF 数据\n", (unsigned)file_size);
        return result;
    }

    fd = ext4_open(fs, inode);
    if (fd < 0) {
        kfree(elf_data);
        return result;
    }

    int total = 0;
    int n;
    while ((n = ext4_read(fs, fd, elf_data + total, 65536)) > 0) {
        total += n;
    }
    ext4_close(fs, fd);

    result = elf_load_from_memory(elf_data, (size_t)total, load_base);
    kfree(elf_data);
    return result;
}

elf_load_result_t elf_load_from_memory(const uint8_t *elf_data, size_t size,
                                        uintptr_t load_base)
{
    (void)load_base; /* ELF 文件自带虚拟地址 */
    return elf_load_internal(elf_data, size, 0, NULL, NULL);
}

int elf_setup_stack(uintptr_t page_table_root, uintptr_t stack_top,
                    int argc, const char *argv[], const char *envp[])
{
    (void)argc; (void)argv; (void)envp;

    /* 分配用户栈 (256KB) */
    for (uintptr_t va = stack_top - USER_STACK_SIZE; va < stack_top; va += PAGE_SIZE) {
        uint8_t *phys_page = (uint8_t *)alloc_page();
        if (!phys_page) return -1;
        memset(phys_page, 0, PAGE_SIZE);

        if (map_page(page_table_root, va, (uintptr_t)phys_page,
                     PTE_USER_RW) < 0) {
            free_page(phys_page);
            return -1;
        }
    }

    return 0;
}

