/* 全局测试表 */
static test_script_t g_scripts[MAX_TEST_SCRIPTS];
static int g_script_count = 0;

/* 外部引用 */
extern ext4_fs_t g_ext4_fs;

void test_runner_init(void) {
    memset(g_scripts, 0, sizeof(g_scripts));
    g_script_count = 0;
    printf("[test] 测试运行器初始化完成\n");
}

/* 从文件名提取测试组名
 * "basic_testcode.sh" -> "basic"
 */
static void extract_group_name(const char *filename, char *group_name, size_t max_len) {
    const char *end = strstr(filename, "_testcode.sh");
    if (!end) end = strstr(filename, ".sh");

    size_t len;
    if (end) {
        len = (size_t)(end - filename);
    } else {
        len = strlen(filename);
    }

    if (len >= 3 && strncmp(filename + len - 3, ".sh", 3) == 0) {
        len -= 3;
    }

    if (len >= max_len) len = max_len - 1;

    memcpy(group_name, filename, len);
    group_name[len] = '\0';
}

/* 解析 .sh 脚本文件 */
static int parse_script(ext4_fs_t *fs, const char *script_name, test_script_t *script) {
    uint32_t script_inode;
    uint8_t script_type;
    if (ext4_lookup(fs, EXT4_ROOT_INO, script_name, &script_inode, &script_type) < 0) {
        return -1;
    }

    int fd = ext4_open(fs, script_inode);
    if (fd < 0) return -1;

    uint64_t fsize = ext4_file_size(fs, fd);
    if (fsize > 65536) fsize = 65536;

    char *script_buf = (char *)kmalloc((size_t)fsize + 1);
    if (!script_buf) {
        ext4_close(fs, fd);
        return -1;
    }

    int total = ext4_read(fs, fd, script_buf, (uint32_t)fsize);
    ext4_close(fs, fd);

    if (total <= 0) {
        kfree(script_buf);
        return -1;
    }
    script_buf[total] = '\0';

    /* 提取组名 */
    extract_group_name(script_name, script->name, sizeof(script->name));
    strncpy(script->filename, script_name, sizeof(script->filename) - 1);

    /* 按行解析 */
    script->cmd_count = 0;
    char *line = script_buf;
    char *next_line;

    while (line && *line && script->cmd_count < MAX_SCRIPT_CMDS) {
        next_line = strchr(line, '\n');
        if (next_line) {
            *next_line = '\0';
            next_line++;
        }

        /* 跳过前导空白 */
        while (*line == ' ' || *line == '\t') line++;

        /* 跳过空行和注释 */
        if (*line == '\0' || *line == '#') {
            line = next_line;
            continue;
        }

        /* 查找 ELF 引用 */
        char *elf_ref = strstr(line, ".elf");
        if (elf_ref) {
            char *name_start = elf_ref;
            while (name_start > line &&
                   *(name_start - 1) != ' ' &&
                   *(name_start - 1) != '\t' &&
                   *(name_start - 1) != '/' &&
                   *(name_start - 1) != '.' &&
                   *(name_start - 1) != '"' &&
                   *(name_start - 1) != '\'') {
                name_start--;
            }

            if (name_start[0] == '.' && name_start[1] == '/') {
                name_start += 2;
            } else if (name_start[0] == '/') {
                name_start += 1;
            }

            size_t name_len = (size_t)(elf_ref + 4 - name_start);

            test_cmd_t *cmd = &script->cmds[script->cmd_count];
            cmd->type = CMD_TYPE_ELF;
            memcpy(cmd->elf_name, name_start, name_len);
            cmd->elf_name[name_len] = '\0';
            strncpy(cmd->full_cmd, line, sizeof(cmd->full_cmd) - 1);
            script->cmd_count++;
        }

        line = next_line;
    }

    kfree(script_buf);
    return script->cmd_count;
}

int test_runner_discover(ext4_fs_t *fs) {
    g_script_count = 0;

    ext4_dir_entry_t entries[256];
    int count = ext4_readdir(fs, EXT4_ROOT_INO, entries, 256);

    printf("[test] 根目录共有 %d 个目录项\n", count);

    for (int i = 0; i < count && g_script_count < MAX_TEST_SCRIPTS; i++) {
        const char *name = entries[i].name;

        if (name[0] == '.' && (name[1] == '\0' || (name[1] == '.' && name[2] == '\0'))) {
            continue;
        }

        if (str_endswith(name, "_testcode.sh")) {
            printf("[test] 发现测试脚本: %s\n", name);

            if (parse_script(fs, name, &g_scripts[g_script_count]) > 0) {
                printf("[test]   组='%s', %d 个命令\n",
                       g_scripts[g_script_count].name,
                       g_scripts[g_script_count].cmd_count);
            } else {
                extract_group_name(name, g_scripts[g_script_count].name,
                                  sizeof(g_scripts[g_script_count].name));
                strncpy(g_scripts[g_script_count].filename, name,
                        sizeof(g_scripts[g_script_count].filename) - 1);
                g_scripts[g_script_count].cmd_count = 0;
            }
            g_script_count++;
        }
    }

    printf("[test] 共发现 %d 个测试脚本\n", g_script_count);
    return g_script_count;
}

/* 运行单个 ELF 测试程序
 * 这是关键函数: 加载 ELF, 创建进程, 进入用户态执行, 等待退出 */
static int run_elf_test(ext4_fs_t *fs, const char *elf_name) {
    printf("\n[test] --- 运行: %s ---\n", elf_name);

    /* 1. 查找 ELF 文件 */
    uint32_t elf_inode;
    uint8_t elf_type;
    if (ext4_lookup(fs, EXT4_ROOT_INO, elf_name, &elf_inode, &elf_type) < 0) {
        printf("[test] 错误: 找不到文件 '%s'\n", elf_name);
        return -1;
    }

    /* 2. 加载 ELF 到用户空间 */
    elf_load_result_t load_result = elf_load(fs, elf_inode, USER_LOAD_BASE);
    if (!load_result.success) {
        printf("[test] 错误: ELF 加载失败 '%s'\n", elf_name);
        return -1;
    }

    /* 3. 创建进程 */
    int pid = proc_create(load_result.entry_point, load_result.page_table_root);
    if (pid < 0) {
        printf("[test] 错误: 进程创建失败\n");
        return -1;
    }

    proc_set_current(pid);
    process_t *proc = proc_get_current();

    printf("[test] 进程 PID=%d, entry=0x%x, stack=0x%x, pgtable=0x%x\n",
           pid, (unsigned)load_result.entry_point,
           (unsigned)proc->user_stack,
           (unsigned)load_result.page_table_root);

    /* 4. 进入用户态执行
     *
     * enter_user_process() 内部:
     *   1. 保存内核上下文 (ra, sp, satp)
     *   2. 切换到用户页表
     *   3. sret 到用户态
     *   4. 用户进程运行...
     *   5. 用户进程调用 exit 系统调用
     *   6. sys_exit 设置 g_return_to_kernel=1
     *   7. trap_entry.S 返回到保存的内核 ra
     *   8. enter_user_process() 返回退出码
     */
    int exit_code = enter_user_process(load_result.entry_point,
                                        proc->user_stack,
                                        load_result.page_table_root);

    /* 5. 清理 */
    printf("[test] 进程 %d 已退出, exit_code=%d\n", pid, exit_code);
    proc_destroy(pid);
    proc_set_current(-1);

    return exit_code;
}

void test_runner_run_all(ext4_fs_t *fs) {
    printf("\n========================================\n");
    printf("  uuOS 测试运行器启动\n");
    printf("  共 %d 个测试组待执行\n", g_script_count);
    printf("========================================\n\n");

    for (int i = 0; i < g_script_count; i++) {
        test_script_t *script = &g_scripts[i];

        /* 输出测试组开始标记 */
        printf("#### OS COMP TEST GROUP START %s ####\n", script->name);

        if (script->cmd_count == 0) {
            printf("[test] 测试组 '%s' 无命令, 跳过\n", script->name);
        } else {
            /* 串行执行组内所有命令 */
            for (int j = 0; j < script->cmd_count; j++) {
                test_cmd_t *cmd = &script->cmds[j];

                if (cmd->type == CMD_TYPE_ELF) {
                    int rc = run_elf_test(fs, cmd->elf_name);
                    if (rc < 0) {
                        printf("[test] 测试 '%s' 执行失败\n", cmd->elf_name);
                    }
                } else {
                    printf("[test] 跳过命令: %s\n", cmd->full_cmd);
                }
            }
        }

        /* 输出测试组结束标记 */
        printf("#### OS COMP TEST GROUP END %s ####\n\n", script->name);
    }

    printf("========================================\n");
    printf("  所有测试组执行完毕\n");
    printf("========================================\n\n");
}

