OUTPUT_ARCH("riscv64")
ENTRY(_start)

SECTIONS
{
    /* 内核加载地址: OpenSBI 默认将内核加载到 0x80200000 */
    . = 0x80200000;

    /* 内核镜像起始 */
    _kernel_start = .;

    .text : {
        KEEP(*(.text.boot))
        *(.text .text.*)
        . = ALIGN(8);
    }

    .rodata : {
        *(.rodata .rodata.*)
        . = ALIGN(8);
    }

    .data : {
        *(.data .data.*)
        . = ALIGN(8);
    }

    . = ALIGN(4096);

    /* BSS 段 */
    .bss : {
        _bss_start = .;
        *(.bss .bss.*)
        *(COMMON)
        . = ALIGN(8);
        _bss_end = .;
    }

    /* 内核堆区域 */
    . = ALIGN(4096);
    _heap_start = .;
    _kernel_end = .;

    /* 用户态内存从此开始 (4MB 对齐, 用于 Sv39) */
    . = ALIGN(0x400000);
    _user_memory_start = .;

    /DISCARD/ : {
        *(.comment)
        *(.note)
        *(.eh_frame)
        *(.debug*)
    }
}

/* LoongArch 链接器脚本 - uuOS 内核 */

OUTPUT_ARCH("loongarch64")
ENTRY(_start)

SECTIONS
{
    /* LoongArch QEMU virt 内核加载地址 */
    . = 0x90000000;

    _kernel_start = .;

    .text : {
        KEEP(*(.text.boot))
        *(.text .text.*)
        . = ALIGN(8);
    }

    .rodata : {
        *(.rodata .rodata.*)
        . = ALIGN(8);
    }

    .data : {
        *(.data .data.*)
        . = ALIGN(8);
    }

    . = ALIGN(4096);

    .bss : {
        _bss_start = .;
        *(.bss .bss.*)
        *(COMMON)
        . = ALIGN(8);
        _bss_end = .;
    }

    . = ALIGN(4096);
    _heap_start = .;
    _kernel_end = .;

    . = ALIGN(0x400000);
    _user_memory_start = .;

    /DISCARD/ : {
        *(.comment)
        *(.note)
        *(.eh_frame)
        *(.debug*)
    }
}

